+fn utf8_index_strings(labels: &[IndexLabel]) -> Vec<String> {
+    labels
+        .iter()
+        .map(|label| match label {
+            IndexLabel::Utf8(value) => value.clone(),
+            _ => unreachable!("drop row helpers require Utf8 index labels"),
+        })
+        .collect()
+}
